try {
    def client = new ThanosClient(hostProps)
    def metrics = [
        "cpu_usage_rate": 'rate(kubevirt_vmi_cpu_usage_seconds_total[5m])',
        "cpu_system_rate": 'rate(kubevirt_vmi_cpu_system_usage_seconds_total[5m])',
        "cpu_user_rate": 'rate(kubevirt_vmi_cpu_user_usage_seconds_total[5m])',
        "vcpu_wait_rate": 'rate(kubevirt_vmi_vcpu_wait_seconds_total[5m])',
        "vcpu_delay_rate": 'rate(kubevirt_vmi_vcpu_delay_seconds_total[5m])'
    ]
    def allData = [:]

    // vcpu_seconds aggregated by VM
    client.queryGroupedByKey('sum by (namespace, name) (rate(kubevirt_vmi_vcpu_seconds_total[5m]))', ["namespace", "name"]).each { k, v ->
        if (!allData[k]) allData[k] = [:]
        allData[k]["vcpu_seconds_rate"] = v
    }

    metrics.each { dp, query ->
        client.queryGroupedByKey(query, ["namespace", "name"]).each { k, v ->
            if (!allData[k]) allData[k] = [:]
            allData[k][dp] = v
        }
    }

    allData.each { wv, dps ->
        dps.each { dp, val ->
            if (val != null) {
                if (dp == "cpu_usage_rate" || dp == "vcpu_seconds_rate") {
                    def pct = String.format("%.4f", (val as Double) * 100)
                    println "${wv}.${dp.replace('_rate', '_percent')}=${pct}"
                }
                println "${wv}.${dp}=${val}"
            }
        }
    }
    return 0
} catch (Exception e) {
    System.err.println "ERROR: ${e.message}"
    return 1
}
